  if (typeof drainable.once !== 'function') return;
  await new Promise<void>((resolve) => {
    const settle = (): void => {
      drainable.off?.('drain', settle);
      drainable.off?.('error', settle);
      drainable.off?.('close', settle);
      resolve();
